//! End-to-end proof of the node-side signing loop.
//!
//! Closes the loop the verify side already supports: provision a subagent the
//! way `ops::spawn` does (a fresh `a0n-auth` keypair → its DID into a
//! `fleet.json` ledger entry via the public ledger/store API, its secret into a
//! 0600 keyfile via `store::write_agent_key`), then drive it through the public
//! signer + verifier:
//!   (a) a keyfile signature verifies against the ledger DID,
//!   (b) a tampered message fails,
//!   (c) an unknown id fails without panicking.
//!
//! Pure crypto + fs — fast, no inference, gates nothing: runs under plain
//! `cargo test`. Isolated in a per-pid temp `$MONSTER_GUARD_HOME` so it never
//! observes another test's home, and cleaned up at the end.

use a0n_auth::Keypair;

use monster_swarm::budget::Caste;
use monster_swarm::ledger::new_subagent;
use monster_swarm::sign::{sign_with_keyfile, sign_with_secret_hex, verify_subagent_signature};
use monster_swarm::store;

/// Provision a subagent exactly as `ops::spawn` does — fresh keypair, DID in the
/// ledger, secret in the 0600 keyfile — and return its DID for assertions.
fn provision(id: &str) -> String {
    let kp = Keypair::generate();
    let did = kp.did().to_string();

    // Secret → 0600 keyfile (handed to the node by path, never by value).
    store::write_agent_key(id, &kp.secret_hex()).expect("write agent keyfile");

    // DID → fleet.json ledger entry, via the public ledger/store API.
    let mut fleet = store::load_fleet();
    fleet.add(new_subagent(
        id.to_string(),
        format!("agent-{id}"),
        did.clone(),
        "did:key:zSpawner".into(),
        Caste::Scout,
        vec!["net".into()],
        "fat-station".into(),
        vec![],
        60,
        Some(1),
        None,
        false,
        None,
        1,
    ));
    store::save_fleet(&fleet).expect("save fleet ledger");

    did
}

#[test]
fn signing_loop_end_to_end() {
    // Isolated per-pid $MONSTER_GUARD_HOME. This binary is its own process, so
    // setting the env var here cannot race another test's home.
    let home = std::env::temp_dir().join(format!("monster-swarm-signloop-{}", std::process::id()));
    let _ = std::fs::remove_dir_all(&home);
    std::fs::create_dir_all(&home).expect("create isolated home");
    std::env::set_var("MONSTER_GUARD_HOME", &home);

    let id = "siggy";
    let _did = provision(id);

    let msg = b"invoke: decode-next pos=0 token=785";

    // (a) The keyfile owner can sign, and the ledger DID verifies it.
    let sig = sign_with_keyfile(id, msg).expect("sign with keyfile");
    assert!(
        verify_subagent_signature(id, msg, &sig),
        "a keyfile signature must verify against the provisioned ledger DID"
    );

    // (b) Tampering with the message breaks verification.
    let tampered = b"invoke: decode-next pos=1 token=785";
    assert!(
        !verify_subagent_signature(id, tampered, &sig),
        "a signature must not verify over a different message"
    );

    // A signature from a DIFFERENT key (an impostor reusing the real id) fails
    // against the provisioned DID — the keyfile secret is the only thing that
    // verifies, not the id string.
    let impostor = Keypair::generate();
    let forged = sign_with_secret_hex(&impostor.secret_hex(), msg).expect("impostor sign");
    assert!(
        !verify_subagent_signature(id, msg, &forged),
        "a signature from a non-provisioned key must be rejected"
    );

    // (c) An unknown subagent id never verifies — and never panics, even though
    // there is no ledger entry and no keyfile for it.
    assert!(
        !verify_subagent_signature("nobody", msg, &sig),
        "an unknown subagent id must fail to verify"
    );
    // A second provisioned subagent's signature must not verify under the first
    // one's id — DIDs are per-subagent.
    let other_id = "scout-2";
    let _other_did = provision(other_id);
    let other_sig = sign_with_keyfile(other_id, msg).expect("sign with other keyfile");
    assert!(
        verify_subagent_signature(other_id, msg, &other_sig),
        "the second subagent verifies under its own id"
    );
    assert!(
        !verify_subagent_signature(id, msg, &other_sig),
        "one subagent's signature must not verify under another's id"
    );

    // Garbage signature bytes are rejected without panicking.
    assert!(!verify_subagent_signature(id, msg, &[0u8; 8]));
    assert!(!verify_subagent_signature(id, msg, &[]));

    // Cleanup.
    store::remove_agent_key(id);
    store::remove_agent_key(other_id);
    std::env::remove_var("MONSTER_GUARD_HOME");
    let _ = std::fs::remove_dir_all(&home);
}
